// ─── 1. APP ICON — square badge ──────────────────────────────────────────────
function AppIcon({ size=64, radius=null }) {
  const rx = radius !== null ? radius : Math.round(size * 0.18);
  return (
    <svg width={size} height={size} viewBox="0 0 340 340" fill="none">
      <rect width="340" height="340" rx={rx*(340/size)} fill={B.surface}/>
      <rect x="8" y="8" width="324" height="324"
        rx={Math.max(rx*(340/size)-5,2)}
        fill="none" stroke={AMBER} strokeWidth="10" opacity="0.28"/>
      <image href={LOGO_AMBER} x="14" y="14" width="312" height="312"
        preserveAspectRatio="xMidYMid meet"/>
      <text x="326" y="42" textAnchor="end"
        fontFamily="Arial" fontSize="30" fontWeight="700"
        fill={AMBER} opacity="0.6">™</text>
    </svg>
  );
}

// ─── 2. CIRCULAR BADGE — hero stamp, print, social ───────────────────────────
function CircularBadge({ size=160 }) {
  const dots = [0,45,90,135,180,225,270,315].map(deg => {
    const rad = (deg-90)*Math.PI/180;
    return { cx:170+159*Math.cos(rad), cy:170+159*Math.sin(rad), big:deg%90===0 };
  });
  const id = `bb${size}`;
  return (
    <svg width={size} height={size} viewBox="0 0 340 340" fill="none"
      role="img" aria-label="The Borrow Barn badge">
      <defs>
        <path id={`aT${id}`} d="M 30,170 A 140,140 0 0,1 310,170"/>
        <path id={`aB${id}`} d="M 310,170 A 140,140 0 0,1 30,170"/>
        <clipPath id={`cc${id}`}><circle cx="170" cy="170" r="138"/></clipPath>
      </defs>
      {/* Background */}
      <circle cx="170" cy="170" r="165" fill={B.surface}/>
      {/* Outer rings */}
      <circle cx="170" cy="170" r="165" stroke={AMBER} strokeWidth="5.5" fill="none"/>
      <circle cx="170" cy="170" r="151" stroke={AMBER} strokeWidth="0.8" fill="none" opacity="0.2"/>
      {/* Cardinal dots */}
      {dots.map((d,i)=>(
        <circle key={i} cx={d.cx} cy={d.cy}
          r={d.big?5:2.5} fill={d.big?AMBER:CREAM} opacity={d.big?1:0.28}/>
      ))}
      {/* Top arc: THE BORROW BARN */}
      <text fontFamily="'Arial Black',Arial,sans-serif"
        fontWeight="900" fontSize="22" letterSpacing="9" fill={AMBER}>
        <textPath href={`#aT${id}`} startOffset="50%" textAnchor="middle">
          THE BORROW BARN
        </textPath>
      </text>
      {/* Bottom arc: tagline */}
      <text fontFamily="Arial,sans-serif" fontStyle="italic"
        fontWeight="400" fontSize="13" letterSpacing="1.5"
        fill={CREAM} fillOpacity="0.5">
        <textPath href={`#aB${id}`} startOffset="50%" textAnchor="middle">
          Borrow what you need. Lend what you don't.  ™
        </textPath>
      </text>
      {/* Barn logo image — clipped to inner circle */}
      <image href={LOGO_AMBER} x="32" y="32" width="276" height="276"
        clipPath={`url(#cc${id})`} preserveAspectRatio="xMidYMid meet"/>
      {/* Copyright fine print */}
      <text x="170" y="328" textAnchor="middle"
        fontFamily="Arial,sans-serif" fontSize="9" fontWeight="500"
        fill={CREAM} fillOpacity="0.2" letterSpacing="1.5">
        © 2026 THE BORROW BARN · TRANSCEND PM · TM PENDING
      </text>
    </svg>
  );
}

